enable-ps-logging.ps1Project: Suspicious PowerShell Detection EngineeringPurpose: Enable PowerShell Script Block Logging, Module Logging, and Transcription LoggingRun as AdministratorLab use only#Requires -RunAsAdministratorWrite-Host "Enabling PowerShell logging..." -ForegroundColor Cyan1. Enable Script Block Logging$scriptBlockPath = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\PowerShell\ScriptBlockLogging"if (!(Test-Path $scriptBlockPath)) {New-Item $scriptBlockPath -Force | Out-Null}Set-ItemProperty -Path $scriptBlockPath -Name "EnableScriptBlockLogging" -Value 1Set-ItemProperty -Path $scriptBlockPath -Name "EnableScriptBlockInvocationLogging" -Value 1Write-Host "[+] Script Block Logging enabled. Event ID 4104 should be generated." -ForegroundColor Green2. Enable Module Logging$moduleLoggingPath = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\PowerShell\ModuleLogging"if (!(Test-Path $moduleLoggingPath)) {New-Item $moduleLoggingPath -Force | Out-Null}Set-ItemProperty -Path $moduleLoggingPath -Name "EnableModuleLogging" -Value 1$moduleNamesPath = "$moduleLoggingPath\ModuleNames"if (!(Test-Path $moduleNamesPath)) {New-Item $moduleNamesPath -Force | Out-Null}Set-ItemProperty -Path $moduleNamesPath -Name "" -Value ""Write-Host "[+] Module Logging enabled. Event ID 4103 should be generated." -ForegroundColor Green3. Enable Transcription Logging$transcriptionPath = "HKLM:\SOFTWARE\Policies\Microsoft\Windows\PowerShell\Transcription"if (!(Test-Path $transcriptionPath)) {New-Item $transcriptionPath -Force | Out-Null}$transcriptDirectory = "C:\PSTranscripts"if (!(Test-Path $transcriptDirectory)) {New-Item -Path $transcriptDirectory -ItemType Directory -Force | Out-Null}Set-ItemProperty -Path $transcriptionPath -Name "EnableTranscripting" -Value 1Set-ItemProperty -Path $transcriptionPath -Name "EnableInvocationHeader" -Value 1Set-ItemProperty -Path $transcriptionPath -Name "OutputDirectory" -Value $transcriptDirectoryWrite-Host "[+] Transcription Logging enabled. Output directory: C:\PSTranscripts" -ForegroundColor GreenWrite-Host ""Write-Host "All PowerShell logging settings have been enabled." -ForegroundColor CyanWrite-Host "Close and reopen PowerShell before testing logs." -ForegroundColor Yellow